#include "am1_core.h"
#include <stdlib.h>
static int am1_rewrite_first(am1_term **slot){ am1_term *t=*slot; if(!t) return 0; if(t->left && am1_rewrite_first(&t->left)) return 1; if(t->right && am1_rewrite_first(&t->right)) return 1; if(t->rewritten) return 0; switch(t->tag){ case AM1_ORIGIN:{ am1_term *u=am1_new(AM1_UNRESOLVED, am1_new(AM1_POLE_0,NULL,NULL), am1_new(AM1_POLE_1,NULL,NULL)); if(!u) return 0; am1_free(t); *slot=u; return 1; } case AM1_UNRESOLVED:{ am1_term *x=am1_clone(t); am1_term *m=am1_new(AM1_MIRROR, am1_clone(t), NULL); am1_term *u=am1_new(AM1_SELF_ATTEMPT, x, m); if(!u) return 0; am1_free(t); *slot=u; return 1; } case AM1_SELF_ATTEMPT:{ am1_term *left_copy=am1_clone(t->left); am1_term *u=am1_new(AM1_ARTICULATION, am1_clone(t->left), am1_new(AM1_REEXPRESSION, left_copy, NULL)); if(!u) return 0; am1_free(t); *slot=u; return 1; } case AM1_REEXPRESSION:{ am1_term *u=am1_new(AM1_UNRESOLVED, am1_clone(t->left), am1_new(AM1_MIRROR, am1_clone(t->left), NULL)); if(!u) return 0; am1_free(t); *slot=u; return 1; } case AM1_MIRROR: case AM1_ARTICULATION: case AM1_POLE_0: case AM1_POLE_1: default: t->rewritten=1; return 0; }}
am1_term *am1_initial_state(void){ return am1_new(AM1_ORIGIN,NULL,NULL); }
void am1_step(am1_term **root){ if(!root || !*root) return; (void)am1_rewrite_first(root); }
